// Return taskId immediately so frontend can start polling
const generateResult = $('Generate Video Kie1').item.json;
const taskId = generateResult.data?.taskId || generateResult.taskId;

if (!taskId) {
  throw new Error('No taskId received from Veo3.1 API');
}

return {
  taskId: taskId,
  state: 'generating',
  message: 'Video generation started. Polling for status...',
  script: $('Parse Script').item.json.script || ''
};

